### 5. gRPC Service Жхгьўё (ВўѕВЃЂ)

#### ВюёВ╣ў: `notification/src/main/kotlin/com/maum/backend/controller/NotificationGrpcService.kt`

```kotlin
@GrpcService
class NotificationGrpcService(
    private val notificationService: NotificationService,
) : NotificationServiceGrpc.NotificationServiceImplBase() {

    override fun getNotifications(
        request: GetNotificationsRequest,
        responseObserver: StreamObserver<GetNotificationsResponse>,
    ) {
        try {
            val result = notificationService.getNotifications(
                request.userId,
                request.limit,
                request.offset
            )
            responseObserver.onNext(result)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Failed to fetch notifications")
                    .asRuntimeException()
            )
        }
    }

    override fun sendNotification(
        request: SendNotificationRequest,
        responseObserver: StreamObserver<SendNotificationResponse>,
    ) {
        try {
            val result = notificationService.sendNotification(request)
            responseObserver.onNext(result)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(Status.INTERNAL.asRuntimeException())
        }
    }
}
```

#### Service ваѕВЮ┤Вќ┤: `notification/src/main/kotlin/com/maum/backend/service/NotificationService.kt`

```kotlin
@Service
class NotificationService(
    private val notificationRepository: NotificationRepository,
    private val notificationSettingRepository: NotificationSettingRepository,
    private val fcmService: FCMService,
) {
    @Transactional(readOnly = true)
    fun getNotifications(userId: String, limit: Int, offset: Int): GetNotificationsResponse {
        val notifications = notificationRepository
            .findByUserIdOrderByCreatedAtDesc(userId)
            .drop(offset)
            .take(limit)

        return GetNotificationsResponse.newBuilder()
            .addAllNotifications(notifications.map { it.toProto() })
            .setTotal(notificationRepository.count { it.userId == userId }.toLong())
            .build()
    }

    @Transactional
    fun sendNotification(request: SendNotificationRequest): SendNotificationResponse {
        val notification = notificationRepository.save(
            NotificationEntity(
                userId = request.userId,
                title = request.title,
                body = request.body,
                type = request.type,
                metadata = request.metadata,
            )
        )

        // Firebase Cloud MessagingВю╝вАю ВІцВаю ьЉИВІю ВаёВєА
        val fcmSuccess = fcmService.sendPushNotification(
            userId = request.userId,
            title = request.title,
            body = request.body,
            notificationId = notification.id,
        )

        return SendNotificationResponse.newBuilder()
            .setNotificationId(notification.id)
            .setSuccess(fcmSuccess)
            .build()
    }
}
```

