### 6. FCM Service (Firebase Cloud Messaging)

#### ВюёВ╣ў: `notification/src/main/kotlin/com/maum/backend/service/FCMService.kt`

```kotlin
@Service
class FCMService(
    @Value("\${firebase.project-id}")
    private val projectId: String,
    private val userRepository: UserRepository,
) {

    fun sendPushNotification(
        userId: String,
        title: String,
        body: String,
        notificationId: String,
    ): Boolean {
        return try {
            val fcmTokens = getUserFCMTokens(userId)
            for (token in fcmTokens) {
                sendToToken(token, title, body, notificationId)
            }
            fcmTokens.isNotEmpty()
        } catch (e: Exception) {
            log.error("Failed to send FCM notification", e)
            false
        }
    }

    private fun sendToToken(
        token: String,
        title: String,
        body: String,
        notificationId: String,
    ) {
        val message = Message.builder()
            .setToken(token)
            .setNotification(
                Notification.builder()
                    .setTitle(title)
                    .setBody(body)
                    .build()
            )
            .putData("notificationId", notificationId)
            .putData("type", "notification")
            .build()

        FirebaseMessaging.getInstance().send(message)
    }

    fun getUserFCMTokens(userId: String): List<String> {
        // User ВЌћьІ░ьІ░ВЌљВёю FCM ьєаьЂ░ вфЕвАЮ ВА░ьџї
        return userRepository.findById(userId)?.fcmTokens ?: emptyList()
    }
}
```

